// src/pages/MainPage/index.jsx

import React, { useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { fetchAllCategories } from '../../store/slices/categoriesSlice'; // Убедитесь, что Thunk есть
import CategoryItem from '../../components/CategoryItem'; // Компонент для карточки категории
import styles from './MainPage.module.css';
import { fetchCategories } from '../../store/slices/categoriesSlice';

const MainPage = () => {
  const dispatch = useDispatch();
  const { list: categories, status } = useSelector(state => state.categories);

  useEffect(() => {
    // Загружаем категории при первой загрузке страницы
    if (status === 'idle') {
      dispatch(fetchAllCategories());
    }
  }, [status, dispatch]);

  // Выбираем только 4 категории для отображения на главной странице
  const featuredCategories = categories.slice(0, 4); 

  return (
    <div className={styles.mainPage}>

      {/* 1. ГЛАВНЫЙ БАННЕР (Hero Section) */}
      <section className={styles.mainBanner}>
        {/* Контент внутри баннера (текст, кнопка) */}
        <div className={styles.bannerContent}>
          <h1>Скидки на все виды садовой мебели</h1>
          <p>Дополнительная скидка 10% по промокоду GARDEN10</p>
          <button className={styles.shopNowButton}>Купить сейчас</button>
        </div>
      </section>

      {/* 2. СЕКЦИЯ КАТЕГОРИЙ */}
      <section className={styles.categoriesSection}>
        <h2>Категории</h2>
        {status === 'loading' && <p>Загрузка категорий...</p>}
        {status === 'failed' && <p>Ошибка загрузки категорий.</p>}

        <div className={styles.categoriesGrid}>
          {featuredCategories.map(cat => (
            // Здесь предполагается, что CategoryItem отображает название и изображение
            <CategoryItem 
              key={cat.id} 
              id={cat.id} 
              title={cat.title} 
              image={cat.image} 
            />
          ))}
        </div>
      </section>

      {/* 3. СЕКЦИЯ АКЦИЙ (может быть добавлена позже) */}

    </div>
  );
};

export default MainPage;
